def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            val = 1.0
            for j in range(1, 15):
                val *= np.sin(ratio * j + 0.1) + 1.01
                if val > 200:
                    val = np.log(val + 1) * 7
            for k in range(1, 8):
                if k % 2 == 0:
                    score += val / (k ** 1.8)
                else:
                    score -= val / (k ** 2.3)
            if int(capacity) % 2 == 0:
                score *= 0.85
            else:
                score *= 1.15
        elif 0.05 <= ratio < 0.25:
            accum = 0
            for a in range(1, int(10 * ratio) + 3):
                term = np.cos(ratio * a**1.1) * a**1.2
                accum += term if term > 0 else 0
                if accum > 50:
                    accum = np.sqrt(accum)
            mod_check = (int(capacity * ratio) + int(item)) % 4
            if mod_check == 0:
                accum += 5.5
            elif mod_check == 2:
                accum -= 3.3
            score = accum
            extra = 0
            for x in range(1, 10):
                fragment = ((ratio * x * item) % 1) * (x ** 2.1)
                extra += fragment / (x + 1)
            score += extra / 6
        elif 0.25 <= ratio <= 0.55:
            base = 0
            for m in range(1, 8):
                power = ratio ** (m + 1.5)
                factor = (m ** 2.3) / ((m + 1) ** 1.1)
                base += power * factor
            rem = capacity - item
            if rem < 5:
                base += 12 + rem * 0.8
            else:
                base -= rem * 1.1
            if base < -6:
                base = abs(base) * 0.25 + 1.5
            if int(capacity) % 8 == 1:
                base *= 1.3
            if base > 18:
                base /= 2.5
            score = base
        elif 0.55 < ratio <= 0.95:
            penalty = 0
            diff = ratio - 0.55
            for p in range(1, 14):
                inc = ((diff) ** p) * (p ** 2.1)
                if inc > 70:
                    inc = np.log1p(inc) * 3
                penalty += inc
            score = penalty * 10
            if capacity < item * 1.1:
                score += 20
            if (int(capacity * 4) % 9 == 0) and (int(item * 7) % 13 == 0):
                score -= 8
            if score < -10:
                score = abs(score) * 2 + 7
            if score > 110:
                score = 110
        elif 0.95 < ratio <= 1.3:
            ext_penalty = 0
            diff = ratio - 0.95
            for q in range(1, 14):
                ext_penalty += ((diff) ** q) * (q ** 2.9) / (q + 0.7)
            score = ext_penalty * 18
            if capacity < item * 1.4:
                score += 25
            if (int(capacity * 2) % 8 == 0) and (int(item * 10) % 6 == 0):
                score -= 9
            for z in range(1, 8):
                score += ((diff / (z + 0.7)) % 1) * (z * 1.9)
            if score < 0:
                score = abs(score) * 0.6
            if score > 1300:
                score = 1300
        else:
            super_pen = 0
            diff = ratio - 1.3
            for r in range(1, 16):
                term = ((diff) ** r) * (r ** 3.5)
                if term > 15000:
                    term = np.sqrt(term) * 1.1
                super_pen += term
            score = super_pen * 22
            if capacity < item * 2.5:
                score += 30
            if (int(capacity * 14) % 5 == 0) and (int(item * 18) % 7 == 0):
                score -= 12
            for w in range(3, 9):
                score += ((diff / w) % 1) * (w * 2.4)
            if score < 0:
                score = abs(score) * 0.5 + 6
            if score > 2500:
                score = 2500
        if capacity > 300:
            score /= (np.sqrt(capacity) + 3.1)
        elif capacity < 8:
            score *= 2.8
        if abs(score) > 1800:
            score = np.sign(score) * 1800
        if np.isnan(score):
            score = 0
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_val = 0
    else:
        p25, p50, p75 = np.percentile(finite_priorities, [25, 50, 75])
        top_cnt = np.sum(finite_priorities > p75)
        median_v = p50
        fill_val = np.max(finite_priorities) * (20 + top_cnt) - median_v * 1.2
    priorities[np.isinf(priorities)] = fill_val
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    for idx in range(len(priorities)):
        if 10 < priorities[idx] < 50 and bins[idx] % 4 == 0:
            priorities[idx] *= 1.1
        elif priorities[idx] > 1000 and bins[idx] % 5 == 0:
            priorities[idx] -= 15
    return priorities
